//Create an Android Service to handle 4 kind of tasks: "sync", "cleanup", "cleanup_one" & "cleanup_all"

@Service
class SyncService : IntentService("SyncService") {
    override fun onHandleIntent(intent: Intent?) {
        if (intent?.extras == null) return

        val action = intent.action ?: return
        val tag = intent.getStringExtra(Constants.EXTRA_TAG) ?: return

        when(action){
            Constants.ACTIONS.sync -> {
                LogUtils.logD("Sync started")

                //perform sync logic here

                LogUtils.logD("Sync ended")
            }

            Constants.ACTIONS.cleanup ->{
                LogUtils.logD("CleanUp started")

                //perform cleanup logic here

                LogUtils.logD("CleanedUp finished")
            }

            Constants.ACTIONS.cleanupOne -> {
               LogUtils.logD("Cleaning up $tag")

               //Perform task specific cleanup logic

               LogUtils.logD("$tag cleaned.")

           }

         }
    }
}